#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <cuda_runtime.h>
#include <sys/time.h>

#include "../common.h"
#include "../util/timer/timer.h"
#include "./kernel_gpu_cuda_wrapper.h"

extern "C" void setdevice();

__global__ void findK_kernel(long height,
                             knode *knodesD,
                             long knodes_elem,
                             record *recordsD,
                             long *currKnodeD,
                             long *offsetD,
                             int *keysD,
                             record *ansD)
{
    int thid = threadIdx.x;
    int bid = blockIdx.x;

    for (int i = 0; i < height; i++) {
        if ((knodesD[currKnodeD[bid]].keys[thid]) <= keysD[bid] &&
            (knodesD[currKnodeD[bid]].keys[thid + 1] > keysD[bid])) {
            if (knodesD[offsetD[bid]].indices[thid] < knodes_elem) {
                offsetD[bid] = knodesD[offsetD[bid]].indices[thid];
            }
        }
        __syncthreads();
        if (thid == 0) {
            currKnodeD[bid] = offsetD[bid];
        }
        __syncthreads();
    }

    if (knodesD[currKnodeD[bid]].keys[thid] == keysD[bid]) {
        ansD[bid].value = recordsD[knodesD[currKnodeD[bid]].indices[thid]].value;
    }
}

void kernel_gpu_cuda_wrapper(record *records,
                             long records_mem,
                             knode *knodes,
                             long knodes_elem,
                             long knodes_mem,
                             int order,
                             long maxheight,
                             int count,
                             long *currKnode,
                             long *offset,
                             int *keys,
                             record *ans)
{
    cudaError_t err;

#ifdef TIMING
    struct timeval tv_total_start, tv_init_end, tv_mem_alloc_end;
    struct timeval tv_h2d_start, tv_h2d_end;
    struct timeval tv_kernel_start, tv_kernel_end;
    struct timeval tv_d2h_start, tv_d2h_end;
    struct timeval tv_close_start, tv_close_end;
    float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
          d2h_time = 0, close_time = 0, total_time = 0;
    gettimeofday(&tv_total_start, NULL);
#endif

    setdevice();

    record *d_records;
    knode *d_knodes;
    long *d_currKnode;
    long *d_offset;
    int *d_keys;
    record *d_ans;

    err = cudaMalloc((void **)&d_records, records_mem);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMalloc d_records failed\n");
        exit(EXIT_FAILURE);
    }

    err = cudaMalloc((void **)&d_knodes, knodes_mem);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMalloc d_knodes failed\n");
        exit(EXIT_FAILURE);
    }

    err = cudaMalloc((void **)&d_currKnode, count * sizeof(long));
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMalloc d_currKnode failed\n");
        exit(EXIT_FAILURE);
    }

    err = cudaMalloc((void **)&d_offset, count * sizeof(long));
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMalloc d_offset failed\n");
        exit(EXIT_FAILURE);
    }

    err = cudaMalloc((void **)&d_keys, count * sizeof(int));
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMalloc d_keys failed\n");
        exit(EXIT_FAILURE);
    }

    err = cudaMalloc((void **)&d_ans, count * sizeof(record));
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMalloc d_ans failed\n");
        exit(EXIT_FAILURE);
    }

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_total_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
    gettimeofday(&tv_h2d_start, NULL);
#endif
    err = cudaMemcpy(d_records, records, records_mem, cudaMemcpyHostToDevice);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy d_records failed\n");
        exit(EXIT_FAILURE);
    }
    err = cudaMemcpy(d_knodes, knodes, knodes_mem, cudaMemcpyHostToDevice);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy d_knodes failed\n");
        exit(EXIT_FAILURE);
    }
    err = cudaMemcpy(d_currKnode, currKnode, count * sizeof(long), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy d_currKnode failed\n");
        exit(EXIT_FAILURE);
    }
    err = cudaMemcpy(d_offset, offset, count * sizeof(long), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy d_offset failed\n");
        exit(EXIT_FAILURE);
    }
    err = cudaMemcpy(d_keys, keys, count * sizeof(int), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy d_keys failed\n");
        exit(EXIT_FAILURE);
    }
    err = cudaMemcpy(d_ans, ans, count * sizeof(record), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy d_ans failed\n");
        exit(EXIT_FAILURE);
    }
#ifdef TIMING
    gettimeofday(&tv_h2d_end, NULL);
    tvsub(&tv_h2d_end, &tv_h2d_start, &tv);
    h2d_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif

    size_t local_work_size = (order < 1024) ? order : 1024;
    size_t global_work_size = count * local_work_size;

    printf("# of blocks = %d, # of threads/block = %d (ensure that device can handle)\n",
           (int)(global_work_size / local_work_size), (int)local_work_size);

#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif
    findK_kernel<<<count, local_work_size>>>(maxheight, d_knodes, knodes_elem, d_records,
                                             d_currKnode, d_offset, d_keys, d_ans);
    cudaDeviceSynchronize();
#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
    gettimeofday(&tv_d2h_start, NULL);
#endif
    err = cudaMemcpy(ans, d_ans, count * sizeof(record), cudaMemcpyDeviceToHost);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy ans failed\n");
        exit(EXIT_FAILURE);
    }
#ifdef TIMING
    gettimeofday(&tv_d2h_end, NULL);
    tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    cudaFree(d_records);
    cudaFree(d_knodes);
    cudaFree(d_currKnode);
    cudaFree(d_offset);
    cudaFree(d_keys);
    cudaFree(d_ans);

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
    printf("Time spent in different stages of GPU_CUDA KERNEL:\n");
    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif
}

